normalized_obligations.lean_statement:
/-- Greedy optimality step: when considering the next interval in increasing end-time order, if it is compatible with the current last_end, then there exists an optimal solution for the prefix that includes it (or an interval with no later end), so the greedy choice does not reduce the achievable maximum cardinality. -/
∀ (k : Nat),
  let iv := sorted.get k;
  let (count,last_end) := (run_prefix (sorted.take k));
  (last_end = none ∨ iv.1 ≥ last_end.get) →
  (opt_count (sorted.take (k+1)) = opt_count (sorted.take k) + 1)

∀ (k : Nat),
  let iv := sorted.get k;
  let (count,last_end) := (run_prefix (sorted.take k));
  (last_end ≠ none ∧ iv.1 < last_end.get) →
  (opt_count (sorted.take (k+1)) = opt_count (sorted.take k))
